import java.time.LocalDate;
import java.time.LocalTime;
import java.time.LocalDateTime;

// Current date and time
LocalDate today = LocalDate.now();
LocalTime now = LocalTime.now();
LocalDateTime dateTime = LocalDateTime.now();

System.out.println(today);    // e.g.: 2024-04-01
System.out.println(now);      // e.g.: 14:30:15.123
System.out.println(dateTime); // e.g.: 2024-04-01T14:30:15.123

// Verifying immutability
LocalDate d = LocalDate.of(2024, 1, 1);
d.plusDays(10);  // Return value not captured!
System.out.println(d); // 2024-01-01 (unchanged)

LocalDate d2 = d.plusDays(10); // Capture the new instance
System.out.println(d2); // 2024-01-11

import java.time.*;

// of() method
LocalDate d1 = LocalDate.of(2024, 3, 15);       // int specification
LocalDate d2 = LocalDate.of(2024, Month.MARCH, 15); // Month enum
LocalTime t1 = LocalTime.of(14, 30);             // hours, minutes
LocalTime t2 = LocalTime.of(14, 30, 45);         // hours, minutes, seconds
LocalDateTime dt1 = LocalDateTime.of(2024, 3, 15, 14, 30);

// Create from LocalDate + LocalTime
LocalDateTime dt2 = LocalDateTime.of(d1, t1);

// parse() method
LocalDate d3 = LocalDate.parse("2024-03-15");
LocalTime t3 = LocalTime.parse("14:30:45");
LocalDateTime dt3 = LocalDateTime.parse("2024-03-15T14:30:45");

// Invalid value → DateTimeException
try {
    LocalDate invalid = LocalDate.of(2024, 13, 1); // Month is 13
} catch (DateTimeException e) {
    System.out.println(e.getMessage());
}

// Using Month enum
Month m = Month.APRIL;
System.out.println(m.getValue()); // 4
System.out.println(m.name());     // APRIL

// Get number of days from Month enum
System.out.println(Month.FEBRUARY.length(false)); // 28 (non-leap year)
System.out.println(Month.FEBRUARY.length(true));  // 29 (leap year)

// new cannot be used
// LocalDate d = new LocalDate(); // Compile error

