import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.format.FormatStyle;
import java.util.Locale;

LocalDate d = LocalDate.of(2024, 3, 15);

// Predefined formatter
String s1 = d.format(DateTimeFormatter.ISO_LOCAL_DATE);
System.out.println(s1); // 2024-03-15

LocalDateTime dt = LocalDateTime.of(2024, 3, 15, 14, 30);
String s2 = dt.format(DateTimeFormatter.ISO_LOCAL_DATE_TIME);
System.out.println(s2); // 2024-03-15T14:30:00

// Locale-aware format
DateTimeFormatter jf = DateTimeFormatter
    .ofLocalizedDate(FormatStyle.FULL)
    .withLocale(Locale.JAPAN);
System.out.println(d.format(jf)); // 2024年3月15日金曜日

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

LocalDateTime dt = LocalDateTime.of(2024, 3, 15, 14, 30, 45);

// Custom patterns
DateTimeFormatter f1 = DateTimeFormatter.ofPattern("yyyy/MM/dd");
System.out.println(dt.format(f1)); // 2024/03/15

DateTimeFormatter f2 = DateTimeFormatter.ofPattern("yyyy年MM月dd日 HH時mm分");
System.out.println(dt.format(f2)); // 2024年03月15日 14時30分

DateTimeFormatter f3 = DateTimeFormatter.ofPattern("MM-dd-yyyy");
System.out.println(dt.format(f3)); // 03-15-2024

// Note: Using a time pattern with LocalDate causes an error
LocalDate d = LocalDate.of(2024, 3, 15);
DateTimeFormatter f4 = DateTimeFormatter.ofPattern("yyyy/MM/dd HH:mm");
// d.format(f4); // UnsupportedTemporalTypeException

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

// Parse with default format
LocalDate d1 = LocalDate.parse("2024-03-15");
System.out.println(d1); // 2024-03-15

// Parse with custom pattern
DateTimeFormatter f = DateTimeFormatter.ofPattern("yyyy/MM/dd");
LocalDate d2 = LocalDate.parse("2024/03/15", f);
System.out.println(d2); // 2024-03-15

// Parse error
try {
    LocalDate.parse("2024/03/15"); // Not in ISO format, so error
} catch (Exception e) {
    System.out.println("DateTimeParseException");
}

// Parsing LocalDateTime
DateTimeFormatter dtf = DateTimeFormatter.ofPattern("yyyy/MM/dd HH:mm");
LocalDateTime dt = LocalDateTime.parse("2024/03/15 14:30", dtf);
System.out.println(dt); // 2024-03-15T14:30

