import java.time.*;

// Getting ZoneId
ZoneId tokyo = ZoneId.of("Asia/Tokyo");
ZoneId utc = ZoneId.of("UTC");
ZoneId ny = ZoneId.of("America/New_York");

// Creating ZonedDateTime
ZonedDateTime zdt1 = ZonedDateTime.now(tokyo);
System.out.println(zdt1); // e.g.: 2024-03-15T14:30:00+09:00[Asia/Tokyo]

// LocalDateTime to ZonedDateTime
LocalDateTime ldt = LocalDateTime.of(2024, 3, 15, 14, 30);
ZonedDateTime zdt2 = ldt.atZone(tokyo);
System.out.println(zdt2); // 2024-03-15T14:30+09:00[Asia/Tokyo]

// Timezone conversion
ZonedDateTime zdtNY = zdt2.withZoneSameInstant(ny);
System.out.println(zdtNY); // 2024-03-15T01:30-04:00[America/New_York]

import java.time.*;

// Creating an Instant
Instant now = Instant.now();
System.out.println(now); // e.g.: 2024-03-15T05:30:00.123Z

// Create from epoch seconds
Instant epoch = Instant.ofEpochSecond(0);
System.out.println(epoch); // 1970-01-01T00:00:00Z

Instant i = Instant.ofEpochSecond(1000000);
System.out.println(i); // 1970-01-12T13:46:40Z

// Conversion with ZonedDateTime
ZonedDateTime zdt = now.atZone(ZoneId.of("Asia/Tokyo"));
System.out.println(zdt); // Displayed in UTC+9

Instant fromZdt = zdt.toInstant();
System.out.println(fromZdt.equals(now)); // true

// Duration between Instants
Instant i1 = Instant.parse("2024-01-01T00:00:00Z");
Instant i2 = Instant.parse("2024-01-02T12:00:00Z");
Duration d = Duration.between(i1, i2);
System.out.println(d.toHours()); // 36

import java.time.*;

ZoneId tokyo = ZoneId.of("Asia/Tokyo");

// LocalDateTime → ZonedDateTime
LocalDateTime ldt = LocalDateTime.of(2024, 3, 15, 14, 30);
ZonedDateTime zdt = ldt.atZone(tokyo);

// ZonedDateTime → LocalDateTime
LocalDateTime ldt2 = zdt.toLocalDateTime();

// ZonedDateTime → LocalDate / LocalTime
LocalDate ld = zdt.toLocalDate();
LocalTime lt = zdt.toLocalTime();

// ZonedDateTime → Instant
Instant inst = zdt.toInstant();

// Instant → ZonedDateTime
ZonedDateTime zdt2 = inst.atZone(tokyo);

// LocalDateTime → Instant (via ZonedDateTime)
Instant inst2 = ldt.atZone(tokyo).toInstant();

